SELECT b.*, ste.site_nm AS site_nm, cd_bt.code_label AS benefit_type_cd_nm FROM pm_event_benefit b LEFT JOIN sy_site ste ON ste.site_id = b.site_id LEFT JOIN sy_code cd_bt ON cd_bt.code_grp = 'BENEFIT_TYPE' AND cd_bt.code_value = b.benefit_type_cd
ORDER BY b.benefit_id ASC ORDER BY b.benefit_id DESC ORDER BY b.benefit_nm ASC ORDER BY b.benefit_nm DESC ORDER BY b.reg_date ASC ORDER BY b.reg_date DESC ORDER BY b.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

